import psycopg2

def connect():
    try:
        conn = psycopg2.connect(
            host="your_host",
            database="your_database",
            user="your_user",
            password="your_password"
        )
        return conn
    except Exception as e:
        print("Error connecting to PostgreSQL Database", e)
        return None

def search_users(username=None, email=None, role=None, status=None, conn=None):
    cursor = conn.cursor()

    query = "SELECT * FROM users WHERE 1=1"

    if username:
        query += " AND username = %s"
        params = (username,)

    if email:
        query += " AND email = %s"
        params += (email,)

    if role:
        query += " AND role = %s"
        params += (role,)

    if status:
        query += " AND status = %s"
        params += (status,)

    cursor.execute(query, params)
    results = cursor.fetchall()

    return results

conn = connect()
results = search_users(username='john', role='admin', status='active', conn=conn)